  function calculateInvestment() {                                                                                                                                                                     
      // Get inputs with safe parsing                                                                                                                                                                  
      const initial = parseFloat(document.getElementById('initial').value) || 0;                                                                                                                       
      const monthly = parseFloat(document.getElementById('monthly').value) || 0;                                                                                                                       
      const years = parseInt(document.getElementById('years').value) || 0;                                                                                                                             
      const rateInput = parseFloat(document.getElementById('rate').value) || 0;                                                                                                                        
      const taxInput = parseFloat(document.getElementById('tax').value) || 0;                                                                                                                          
      const inflationInput = parseFloat(document.getElementById('inflation').value) || 0;                                                                                                              
      const goal = parseFloat(document.getElementById('goal').value) || 0;                                                                                                                             
      const risk = document.getElementById('risk').value?.toLowerCase() || 'moderate';                                                                                                                 
                                                                                                                                                                                                       
      // Validate required fields                                                                                                                                                                      
      if (years < 0) {                                                                                                                                                                                 
          alert('O tempo de investimento não pode ser negativo.');                                                                                                                                     
          return;                                                                                                                                                                                      
      }                                                                                                                                                                                                
      if (rateInput < 0) {                                                                                                                                                                             
          alert('A taxa de retorno não pode ser negativa.');                                                                                                                                           
          return;                                                                                                                                                                                      
      }                                                                                                                                                                                                
      if (taxInput < 0 || taxInput > 100) {                                                                                                                                                            
          alert('A taxa de imposto deve ser entre 0% e 100%.');                                                                                                                                        
          return;                                                                                                                                                                                      
      }                                                                                                                                                                                                
      if (inflationInput < 0) {                                                                                                                                                                        
          alert('A taxa de inflação não pode ser negativa.');                                                                                                                                          
          return;                                                                                                                                                                                      
      }                                                                                                                                                                                                
                                                                                                                                                                                                       
      // Determine base annual return based on risk profile (optional guidance)                                                                                                                        
      let baseReturn = rateInput;
      if (risk === 'conservative') {                                                                                                                                                                   
          baseReturn = Math.min(baseReturn, 6); // conservative cap                                                                                                                                    
      } else if (risk === 'aggressive') {                                                                                                                                                              
          baseReturn = Math.max(baseReturn, 8); // recommend minimum for aggressive                                                                                                                    
      }                                                                                                                                                                                                
                                                                                                                                                                                                       
      // Convert percentages to decimals                                                                                                                                                               
      const annualReturn = baseReturn / 100;
      const taxRate = taxInput / 100;                                                                                                                                                                  
      const inflationRate = inflationInput / 100;                                                                                                                                                      
                                                                                                                                                                                                       
      if (annualReturn < 0) {                                                                                                                                                                          
          alert('A taxa de retorno anual resultante é negativa. Verifique os valores.');                                                                                                               
          return;                                                                                                                                                                                      
      }           
                                                                                                                                                                                                       
      const months = years * 12;                                                                                                                                                                       
      const monthlyReturn = annualReturn > 0 ? Math.pow(1 + annualReturn, 1/12) - 1 : 0;                                                                                                               
                                                                                                                                                                                                       
      // Future value calculation with safe handling                                                                                                                                                   
      let futureValue;                                                                                                                                                                                 
      if (annualReturn === 0) {                                                                                                                                                                        
          futureValue = initial + monthly * months; // no growth                                                                                                                                       
      } else {                                                                                                                                                                                         
          futureValue = initial * Math.pow(1 + monthlyReturn, months);                                                                                                                                 
          if (monthly > 0 && monthlyReturn > 0) {                                                                                                                                                      
              futureValue += monthly * ((Math.pow(1 + monthlyReturn, months) - 1) / monthlyReturn);                                                                                                    
          }                                                                                                                                                                                            
      }                                                                                                                                                                                                
                                                                                                                                                                                                       
      // Apply taxes on gains (only on profit)                                                                                                                                                         
      const totalInvested = initial + (monthly * months);
      const grossProfit = futureValue - totalInvested;                                                                                                                                                 
      const netProfit = grossProfit > 0 ? grossProfit * (1 - taxRate) : 0;                                                                                                                             
      const finalAmount = totalInvested + netProfit;                                                                                                                                                   
                                                                                                                                                                                                       
      // Adjust for inflation (future value in today's money)                                                                                                                                          
      const inflationAdjusted = inflationRate === 0 ? finalAmount : finalAmount / Math.pow(1 + inflationRate, years);                                                                                  
                                                                                                                                                                                                       
      // Calculate time needed to reach goal (if any)                                                                                                                                                  
      let timeNeeded = 0;                                                                                                                                                                              
      if (goal > 0 && monthlyReturn > 0 && months > 0) {                                                                                                                                               
          // Use iterative approximation to find months needed                                                                                                                                         
          let tempFV = initial;                                                                                                                                                                        
          let monthsNeeded = 0;                                                                                                                                                                        
          const maxMonths = years * 4 || 1200; // reasonable upper bound                                                                                                                               
          while (tempFV < goal && monthsNeeded < maxMonths) {                                                                                                                                          
              monthsNeeded++;                                                                                                                                                                          
              tempFV = initial * Math.pow(1 + monthlyReturn, monthsNeeded);                                                                                                                            
              if (monthly > 0) {                                                                                                                                                                       
                  tempFV += monthly * (Math.pow(1 + monthlyReturn, monthsNeeded) - 1) / monthlyReturn;                                                                                                 
              }                                                                                                                                                                                        
          }                                                                                                                                                                                            
          if (tempFV >= goal) {                                                                                                                                                                        
              timeNeeded = monthsNeeded / 12;                                                                                                                                                          
          } else {                                                                                                                                                                                     
              timeNeeded = years; // cannot reach within bound, use given years                                                                                                                        
          }                                                                                                                                                                                            
      }                                                                                                                                                                                                
                                                                                                                                                                                                       
      // Performance metrics                                                                                                                                                                           
      const returnOnInv = totalInvested > 0 ? (netProfit / totalInvested) * 100 : 0;
      const annualizedReturn = years > 0 ? returnOnInv / years : 0;                                                                                                                                    
                                                                                                                                                                                                       
      // Display results with safety checks                                                                                                                                                            
      const formatCurrency = (val) => isFinite(val) ? `R$ ${val.toFixed(2)}` : 'R$ 0,00';                                                                                                              
      document.getElementById('futureValue').textContent = formatCurrency(finalAmount);                                                                                                                
      document.getElementById('totalInvested').textContent = formatCurrency(totalInvested);                                                                                                            
      document.getElementById('netProfit').textContent = formatCurrency(netProfit);                                                                                                                    
      document.getElementById('timeNeeded').textContent = isFinite(timeNeeded) ? `${timeNeeded.toFixed(1)} anos` : '0 anos';                                                                           
      document.getElementById('effectiveRate').textContent = isFinite(annualizedReturn) ? `${(annualizedReturn * 100).toFixed(2)}% ao ano` : '0% ao ano';                                              
                                                                                                                                                                                                       
      // Goal reached status                                                                                                                                                                           
      const goalReached = isFinite(finalAmount) && finalAmount >= goal;                                                                                                                                
      const goalElement = document.getElementById('goalReached');                                                                                                                                      
      goalElement.textContent = goalReached ? 'Sim' : 'Não';                                                                                                                                           
      goalElement.style.color = goalReached ? '#16a34a' : '#dc2626';                                                                                                                                   
      goalElement.style.fontWeight = 'bold';                                                                                                                                                           
                                                                                                                                                                                                       
      // Provide advice                                                                                                                                                                                
      let advice = '';                                                                                                                                                                                 
      if (goalReached) {                                                                                                                                                                               
          advice = 'Parabéns! Sua estratégia atual está no caminho para alcançar sua meta. Recomendamos revisitar o plano a cada 6 meses para ajustar às mudanças do mercado.';                        
      } else if (isFinite(finalAmount)) {                                                                                                                                                              
          const shortage = goal - finalAmount;                                                                                                                                                         
          if (goal > 0) {                                                                                                                                                                              
              const monthlyIncrease = shortage > 0 && years > 0 ? shortage / (years * 12) : 0;                                                                                                         
              advice = `Para alcançar sua meta de R$ ${goal.toFixed(2)}, você precisará de mais R$ ${shortage.toFixed(2)}. Isso corresponde a um acréscimo médio de R$ ${monthlyIncrease.toFixed(2)}   
  mensais ou um retorno adicional de aproximadamente ${((annualizedReturn * 100).toFixed(2)).toFixed(2)}% ao ano.`;                                                                                    
          } else {                                                                                                                                                                                     
              advice = 'Ajuste sua meta de investimento para um valor realista e superior ao total investido.';                                                                                        
          }                                                                                                                                                                                            
      } else {                                                                                                                                                                                         
          advice = 'Sua simulação não produziu resultados financeiros viáveis. Verifique se os valores inseridos são plausíveis e se a taxa de retorno condiz com o perfil de risco escolhido.';       
      }                                                                                                                                                                                                
      document.getElementById('adviceText').textContent = advice;                                                                                                                                      
                                                                                                                                                                                                       
      // Show results                                                                                                                                                                                  
      document.getElementById('results').style.display = 'block';                                                                                                                                      
                                                                                                                                                                                                       
      // Generate visualizations safely                                                                                                                                                                
      if (isFinite(finalAmount)) {                                                                                                                                                                     
          generateInvestmentChart(initial, monthly, monthlyReturn, months);                                                                                                                            
          generateAnnualBreakdown(initial, monthly, monthlyReturn, taxRate, inflationRate, years);                                                                                                     
      } else {                                                                                                                                                                                         
          document.getElementById('investmentChart').innerHTML = '<p>Erro na simulação financeira. Verifique os valores inseridos.</p>';                                                               
          document.getElementById('annualBreakdown').innerHTML = '';                                                                                                                                   
      }                                                                                                                                                                                                
  }                                                                                                                                                                                                    
                                                                                                                                                                                                       
  function resetInvestmentForm() {                                                                                                                                                                     
      // Clear inputs within the calc-form container
      const container = document.querySelector('.calc-form');                                                                                                                                          
      if (container) {                                                                                                                                                                                 
          container.querySelectorAll('input[type="number"]').forEach(el => el.value = '');                                                                                                             
      }                                                                                                                                                                                                
                                                                                                                                                                                                       
      // Reset risk select                                                                                                                                                                             
      const riskSelect = document.getElementById('risk');
      if (riskSelect) riskSelect.value = 'moderate';                                                                                                                                                   
                                                                                                                                                                                                       
      // Hide all result sections                                                                                                                                                                      
      const results = document.getElementById('results');                                                                                                                                              
      if (results) results.style.display = 'none';                                                                                                                                                     
      document.getElementById('investmentChart').innerHTML = '';                                                                                                                                       
      document.getElementById('annualBreakdown').innerHTML = '';                                                                                                                                       
  }                                                             
